// 'ad' adlı dəyişən yaradıb içində 'Aysel' saxlayırıq
let ad = 'Aysel';

// Dəyişəndən məlumatı alıb ekrana göstəririk
console.log(ad); // nəticə: Aysel

// 'var' ilə dəyişən yaradıram
var gadget = 'telefon';
console.log(gadget); // nəticə: telefon

// Dəyişənin içindəkini dəyişirəm
gadget = 'qulaqlıq';
console.log(gadget); // nəticə: qulaqlıq

// 'let' ilə dəyişən yaradıram
let çanta = 'noutbuk';
console.log(çanta); // nəticə: noutbuk

// Dəyişənin içindəkini dəyişirəm
çanta = 'kitab';
console.log(çanta); // nəticə: kitab

// 'const' ilə dəyişən yaradıram
const sevimliRəng = 'yaşıl';
console.log(sevimliRəng); // nəticə: yaşıl

// Dəyişməyə çalışsam, xəta alaram
// sevimliRəng = 'qırmızı'; // Xəta: Assignment to constant variable

// Üçünü də müqayisə edək

// var ilə dəyişən
var gadget = 'telefon';
gadget = 'planşet'; // dəyişə bilirəm
console.log(gadget); // nəticə: planşet

// let ilə dəyişən
let içki = 'kola';
içki = 'su'; // dəyişə bilirəm
console.log(içki); // nəticə: su

// const ilə dəyişən
const ad = 'Kamran';
// ad = 'Murad'; // Xəta, dəyişə bilmərəm
console.log(ad); // nəticə: Kamran

